components.css:
.ds-window { display: flex; flex-direction: column; border: 2px solid #c0c0c0; background: #e6e2d4; box-shadow: 0 0 0 1px #404040, inset 1px 1px 0 #ffffff, inset -1px -1px 0 #808080; overflow: hidden; font-family: Tahoma, Geneva, sans-serif; }
.ds-window-titlebar { display: flex; align-items: center; justify-content: space-between; min-height: 30px; padding: 4px 8px; background: linear-gradient(90deg, #0a3b73, #1d5ea8); color: #ffffff; font-weight: bold; font-size: 12px; }
.ds-window-icon { display: inline-grid; place-items: center; width: 18px; height: 18px; border: 1px solid rgba(255, 255, 255, 0.6); background: rgba(255, 255, 255, 0.12); margin-right: 6px; }
.ds-window-body { padding: 14px; background: #e6e2d4; font-size: 12px; line-height: 1.4; color: #111111; }
